def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0 or item <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / cap
        base_score = 0.0
        decay = 1.0
        complexity = 1.0
        factor = 1.0
        nested_penalty = 0.0
        bonus = 0.0
        for m in range(1, 15):
            if m % 2 == 0:
                decay *= np.cos(ratio * m) + 1.1
            else:
                decay *= np.sin(cap/(m+1) + ratio) + 1.05
            if m % 4 == 1:
                complexity += (np.tanh(ratio * m) + 0.5) / (m + 1)
            elif m % 5 == 0:
                complexity -= (np.exp(-ratio * m) * 0.1)
            if ratio < 0.1 * m:
                base_score += (m ** 1.8) * np.exp(-ratio*m) / (1 + cap % (m + 3))
            else:
                base_score += np.log1p(m * cap**0.5) / (1 + np.exp(-ratio*m))
            if (cap * m + item) % 13 == 0:
                base_score *= 1.07
            elif (cap + m*m) % 17 == 0:
                base_score *= 0.94
            if m == 7:
                for n in range(1, 8):
                    val = cap - item * n**1.5
                    if val > 0:
                        if val % (n + 3) == 0:
                            nested_penalty += np.log1p(val) / (n + 2)
                        else:
                            nested_penalty -= np.sqrt(abs(val)) / (n + 4)
                    else:
                        nested_penalty -= abs(val)**1.1 / (n + 5)
            if ratio > 0.7 and m % 3 == 0:
                factor *= 1.12 + 0.015 * m
            elif ratio < 0.15 and m % 2 == 0:
                factor *= 0.91 - 0.012 * m
            if m % 6 == 0:
                trig = np.tanh((cap % (m + 5)) * ratio)
                bonus += trig * (m/10.) * (-1 if cap % 3 == 0 else 1)
        score = base_score * complexity + nested_penalty * 0.9 + bonus
        score *= decay * factor
        if score < 0:
            score = -score * (np.log1p(cap + item*2) + np.sqrt(cap) / (1 + ratio))
        else:
            if cap > item * 5:
                score = -score / (np.sqrt(cap) + 2) * (1 + ratio*1.5)
            else:
                score = -score / (cap + 5) * np.exp(-ratio**2 * 1.2)
        if ratio > 0.9:
            score *= 1.18
        elif ratio < 0.03:
            score *= 0.7
        if cap % 3 == 0 and cap % 5 == 0:
            score *= 1.03
        elif cap % 2 == 1 and cap % 7 == 0:
            score *= 0.97
        priorities[i] = score
    return priorities
